/// <reference types="@react-three/fiber" />
'use client';

import { useRef, useState, Suspense } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { Image, Text, PerspectiveCamera } from '@react-three/drei';
import * as THREE from 'three';

interface SceneProject {
  id: number;
  title: string;
  category: string;
  image: string;
}

function Panel({ project, index, total, progress, onSelect, hoveredId, setHoveredId }: { 
  project: SceneProject; 
  index: number; 
  total: number; 
  progress: number;
  onSelect: () => void;
  hoveredId: number | null;
  setHoveredId: (id: number | null) => void;
}) {
  const ref = useRef<THREE.Group>(null);
  const meshRef = useRef<THREE.Mesh>(null);
  
  const panelWidth = 5.5; 
  const panelHeight = 7.5;
  const radius = 6.5; // Reduced radius for "padat" (more compact) spacing
  const baseAngle = (index / total) * Math.PI * 2;

  useFrame((state, delta) => {
    if (!ref.current) return;
    
    // Angle rotation based on global scroll progress
    const currentAngle = baseAngle - (progress * Math.PI * 1.2);
    
    // Position on a circle
    const x = Math.sin(currentAngle) * radius;
    const z = Math.cos(currentAngle) * radius - radius + 3; 
    
    ref.current.position.x = THREE.MathUtils.lerp(ref.current.position.x, x, delta * 4);
    ref.current.position.z = THREE.MathUtils.lerp(ref.current.position.z, z, delta * 4);
    
    const isHovered = hoveredId === project.id;
    const faceAngle = -currentAngle; 
    
    const targetRotY = faceAngle;
    const targetScale = isHovered ? 1.1 : 1;

    ref.current.rotation.y = THREE.MathUtils.lerp(ref.current.rotation.y, targetRotY, delta * 6);
    ref.current.scale.setScalar(THREE.MathUtils.lerp(ref.current.scale.x, targetScale, delta * 6));
    
    // Visibility logic: only vivid when close to front
    const visibility = Math.cos(currentAngle); 
    const opacity = THREE.MathUtils.mapLinear(visibility, -0.5, 1, 0, 1);
    
    if (meshRef.current) {
        // @ts-ignore
        meshRef.current.material.opacity = THREE.MathUtils.lerp(meshRef.current.material.opacity, isHovered ? 1 : Math.max(0, opacity), delta * 4);
        // @ts-ignore
        meshRef.current.material.transparent = true;
    }
  });

  return (
    <group 
      ref={ref} 
      onClick={onSelect}
      onPointerOver={() => setHoveredId(project.id)}
      onPointerOut={() => setHoveredId(null)}
    >
      <Image 
        ref={meshRef}
        url={project.image} 
        scale={[panelWidth, panelHeight]} 
        toneMapped={false}
        transparent
      />
      
      <group position={[0, -panelHeight / 2 + 0.8, 0.1]}>
         <Text
           fontSize={0.35}
           color="#000000"
           anchorX="center"
           anchorY="middle"
           fillOpacity={hoveredId === project.id ? 1 : 0}
         >
           {project.title}
         </Text>
         <Text
           position={[0, -0.35, 0]}
           fontSize={0.14}
           color="#22D3EE"
           anchorX="center"
           anchorY="middle"
           fillOpacity={hoveredId === project.id ? 1 : 0}
         >
           {project.category}
         </Text>
      </group>

      <mesh position={[0, 0, -0.01]}>
        <planeGeometry args={[panelWidth + 0.1, panelHeight + 0.1]} />
        <meshBasicMaterial color="#22D3EE" transparent opacity={hoveredId === project.id ? 0.2 : 0} />
      </mesh>
    </group>
  );
}

function Rig() {
  const { camera, mouse } = useThree();
  const vec = new THREE.Vector3();
  
  return useFrame(() => {
    camera.position.lerp(vec.set(mouse.x * 0.5, mouse.y * 0.3, 12), 0.05);
    camera.lookAt(0, 0, 0);
  });
}

export default function PortfolioScene({ 
  projects,
  onSelectProject, 
  progress 
}: { 
  projects: SceneProject[];
  onSelectProject: (id: number) => void;
  progress: number;
}) {
  const [hoveredId, setHoveredId] = useState<number | null>(null);

  return (
    <div className="w-full h-full bg-white">
      <Canvas 
        gl={{ antialias: true, alpha: true }} 
        dpr={[1, 1.5]}
        style={{ touchAction: 'pan-y' }} // Allow vertical scroll on touch
      >
        <PerspectiveCamera makeDefault position={[0, 0, 15]} fov={40} />
        <Suspense fallback={null}>
          <group position={[0, 0, -2]}>
            {projects.map((project, i) => (
              <Panel 
                key={project.id} 
                project={project} 
                index={i} 
                total={projects.length} 
                progress={progress}
                onSelect={() => onSelectProject(project.id)}
                hoveredId={hoveredId}
                setHoveredId={setHoveredId}
              />
            ))}
          </group>
          <ambientLight intensity={1} />
        </Suspense>
        <Rig />
      </Canvas>
    </div>
  );
}
